Actionscript.script:
this._lockroot = false;
this._visible = false;
stop();

if(isNaN(_root.音效音量)) _root.音效音量 = 100;

this.soundDict = new Object();
this.soundLastTime = new Object();

this.minInterval = 90; //相同声音播放的最小间隔

function 播放音效(音效id, 音量乘数, 声音源){
	if(!soundDict[音效id]){
		//_root.发布消息("new sound "+ 音效id);
		soundDict[音效id] = new Sound(this);
		soundDict[音效id].attachSound(音效id);
	}
	var time = getTimer();
	//若两次播放声音小于最小间隔则无法播放
	if(!isNaN(soundLastTime[音效id]) && time - soundLastTime[音效id] < this.minInterval) return false;
	soundLastTime[音效id] = time;
	音量乘数 = (音量乘数 >= 1 || 音量乘数 <= 0) ? 1 : 音量乘数;
	var 音量 = Math.floor(音量乘数 * _root.音效音量);
	音量 = Math.max(音量, 1);
	//soundDict[音效id].setVolume(音量);
	soundDict[音效id].start(0,1);
	return true;
}
